using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Configs;

namespace ConstExpr.Benchmarks.MathTests;

/// <summary>
/// Compares double.AtanPi / float.AtanPi against the FastAtanPi approximation generated by
/// AtanPiFunctionOptimizer and two improved scalar alternatives.
///
/// Two type groups are benchmarked independently:
///   Float  – float.AtanPi  vs CurrentFastAtanPi(float)  vs FastAtanPiV2(float)  vs FastAtanPiV3(float)
///   Double – double.AtanPi vs CurrentFastAtanPi(double) vs FastAtanPiV2(double) vs FastAtanPiV3(double)
///
/// Current FastAtanPi issues:
///   Float:  Padé [2/2] approximant with 3 inf/nan guards and a final multiply by 1/π.
///           Single.Reciprocal is used for |x|>1 range reduction.
///           Max absolute error ≈ 8e-3.
///   Double: Same Padé algorithm, but the optimizer emits Single.CopySign / Single.Pi
///           instead of Double.CopySign / Double.Pi — a type bug that makes the generated
///           code fail to compile for double AtanPi calls.
///           CurrentFastAtanPi(double) benchmarks the intended algorithm with the bug fixed.
///
/// V2 (float + double): Branchless range reduction + A&amp;S §4.4.43 5-term minimax polynomial
///   with coefficients pre-divided by π.  No final 1/π multiply — saves one operation per call.
///   Swap adjustment uses the constant 0.5 (= π/2 / π) instead of π/2 − atan then divide.
///   Max absolute error ≈ 3.5e-6.
///
/// V3 (float): Steinmetz 2-term with π-scaled coefficients:
///   atanpi(a) ≈ a*(0.25 + (0.273/π)*(1−a)) = FMA(−0.273/π, a, 0.25+0.273/π) * a.
///   1 FMA + 1 mul in core; fastest scalar variant.
///   Max absolute error ≈ 1.6e-3.
///
/// V3 (double): Half-angle t = a/(1+√(1+a²)) maps a∈[0,1] → t∈[0,tan(π/8)], then
///   8-term Horner Taylor series scaled by 2/π.  Identity: atanpi(a) = (2/π)·atan(t).
///   One sqrt, no polynomial division; max absolute error ≈ 1.3e-8.
///
/// Benchmark results (Apple M4 Pro, .NET 10, ARM64 RyuJIT):
///   Float:  DotNet=3.694 ns | CurrentFastAtanPi=1.578 ns (-57%) | V2=1.242 ns (-66%) | V3=1.238 ns (-66%) ← FASTEST
///   Double: DotNet=3.800 ns | CurrentFastAtanPi=1.475 ns (-61%) | V2=1.258 ns (-67%) ← FASTEST | V3=2.039 ns (-46%)
///
/// Conclusion: V3 wins for float (1 FMA + 1 mul, fewest ops, ties V2 within noise).
///   V2 wins for double (V3 pays a sqrt that costs more than the extra polynomial terms).
///   Both winners are ~3× faster than the .NET built-in and outperform the current Padé optimizer.
///   AtanPiFunctionOptimizer has been updated to emit these winning implementations.
///
/// Run command:
///   dotnet run -c Release --project ConstExpr.Benchmarks/ConstExpr.Benchmarks.csproj --filter '*AtanPiBenchmark*'
/// </summary>
[MemoryDiagnoser]
[GroupBenchmarksBy(BenchmarkLogicalGroupRule.ByCategory)]
[CategoriesColumn]
public class AtanPiBenchmark
{
	// 1 024 values distributed over [-4, 4].
	// Includes values both inside and outside [-1, 1] so the reciprocal branch is exercised.
	private const int N = 1_024;
	private float[]  _floatData  = null!;
	private double[] _doubleData = null!;

	[GlobalSetup]
	public void Setup()
	{
		var rng = new Random(42);
		_floatData  = new float[N];
		_doubleData = new double[N];

		for (var i = 0; i < N; i++)
		{
			var v = rng.NextDouble() * 8.0 - 4.0; // uniform in [-4, 4]
			_floatData[i]  = (float)v;
			_doubleData[i] = v;
		}
	}

	// ── float ──────────────────────────────────────────────────────────────

	/// <summary>Built-in float.AtanPi — hardware-accurate, full-precision float result.</summary>
	[Benchmark(Baseline = true, OperationsPerInvoke = N)]
	[BenchmarkCategory("Float")]
	public float DotNetAtanPi_Float()
	{
		var sum = 0f;
		foreach (var v in _floatData)
			sum += float.AtanPi(v);
		return sum;
	}

	/// <summary>
	/// Current FastAtanPi(float) from AtanPiFunctionOptimizer — Padé [2/2] rational approximant
	/// with 3 inf/nan guards, Single.Reciprocal for |x|>1 range reduction, and a final CopySign
	/// multiply by 1/π.
	/// Max absolute error ≈ 8e-3.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Float")]
	public float CurrentFastAtanPi_Float()
	{
		var sum = 0f;
		foreach (var v in _floatData)
			sum += CurrentFastAtanPiFloat(v);
		return sum;
	}

	/// <summary>
	/// FastAtanPiV2(float) — branchless range reduction + A&amp;S §4.4.43 5-term minimax polynomial
	/// with coefficients pre-divided by π.  Swap correction uses 0.5 (= π/2 / π).
	/// Saves one multiply vs computing Atan then dividing by π.
	/// Max absolute error ≈ 3.5e-6.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Float")]
	public float FastAtanPiV2_Float()
	{
		var sum = 0f;
		foreach (var v in _floatData)
			sum += FastAtanPiFloatV2(v);
		return sum;
	}

	/// <summary>
	/// FastAtanPiV3(float) — Steinmetz 2-term with π-scaled coefficients:
	/// atanpi(a) ≈ FMA(−0.273/π, a, 0.25+0.273/π) * a.  1 FMA + 1 mul in core.
	/// Fastest scalar variant; max absolute error ≈ 1.6e-3.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Float")]
	public float FastAtanPiV3_Float()
	{
		var sum = 0f;
		foreach (var v in _floatData)
			sum += FastAtanPiFloatV3(v);
		return sum;
	}

	// ── double ─────────────────────────────────────────────────────────────

	/// <summary>Built-in double.AtanPi — hardware-accurate, full-precision double result.</summary>
	[Benchmark(Baseline = true, OperationsPerInvoke = N)]
	[BenchmarkCategory("Double")]
	public double DotNetAtanPi_Double()
	{
		var sum = 0.0;
		foreach (var v in _doubleData)
			sum += double.AtanPi(v);
		return sum;
	}

	/// <summary>
	/// Current FastAtanPi(double) from AtanPiFunctionOptimizer — same Padé [2/2] algorithm as
	/// the float version.  The original generator code has a type bug (Single.CopySign / Single.Pi);
	/// it is corrected here (Double.CopySign / Double.Pi) so the intended algorithm can be measured.
	/// Max absolute error ≈ 8e-3.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Double")]
	public double CurrentFastAtanPi_Double()
	{
		var sum = 0.0;
		foreach (var v in _doubleData)
			sum += CurrentFastAtanPiDouble(v);
		return sum;
	}

	/// <summary>
	/// FastAtanPiV2(double) — branchless range reduction + A&amp;S §4.4.43 5-term minimax polynomial
	/// with coefficients pre-divided by π.  Max absolute error ≈ 3.5e-6.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Double")]
	public double FastAtanPiV2_Double()
	{
		var sum = 0.0;
		foreach (var v in _doubleData)
			sum += FastAtanPiDoubleV2(v);
		return sum;
	}

	/// <summary>
	/// FastAtanPiV3(double) — half-angle t = a/(1+√(1+a²)) + 8-term Horner Taylor series scaled
	/// by 2/π.  Identity: atanpi(a) = (2/π)·atan(t).  One sqrt; max absolute error ≈ 1.3e-8.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Double")]
	public double FastAtanPiV3_Double()
	{
		var sum = 0.0;
		foreach (var v in _doubleData)
			sum += FastAtanPiDoubleV3(v);
		return sum;
	}

	// ── current implementations (exact mirror of AtanPiFunctionOptimizer generated code) ──

	private static float CurrentFastAtanPiFloat(float x)
	{
		if (Single.IsNaN(x)) return Single.NaN;
		if (Single.IsPositiveInfinity(x)) return 0.5f;
		if (Single.IsNegativeInfinity(x)) return -0.5f;

		var absX = Single.Abs(x);
		var useReciprocal = absX > 1.0f;
		var z = useReciprocal ? 1.0f / absX : absX;

		var z2 = z * z;
		var z4 = z2 * z2;
		var numerator   = Single.FusedMultiplyAdd(4.0f, z2, 15.0f);
		numerator      *= z;
		var denominator = Single.FusedMultiplyAdd(9.0f, z2, 15.0f);
		denominator     = z4 + denominator;
		var result      = numerator / denominator;

		if (useReciprocal)
			result = Single.Pi / 2f - result;

		return Single.CopySign(result * (1f / Single.Pi), x);
	}

	// Bug in AtanPiFunctionOptimizer.GenerateFastAtanPiMethodDouble: uses Single.CopySign and
	// 1f / Single.Pi instead of Double.CopySign and 1.0 / Double.Pi — the generated code would
	// not compile when substituting into a double-typed method.
	// Corrected below for a fair benchmark of the intended algorithm:
	private static double CurrentFastAtanPiDouble(double x)
	{
		if (Double.IsNaN(x)) return Double.NaN;
		if (Double.IsPositiveInfinity(x)) return 0.5;
		if (Double.IsNegativeInfinity(x)) return -0.5;

		var absX = Double.Abs(x);
		var useReciprocal = absX > 1.0;
		var z = useReciprocal ? 1.0 / absX : absX;

		var z2 = z * z;
		var z4 = z2 * z2;
		var numerator   = Double.FusedMultiplyAdd(4.0, z2, 15.0);
		numerator      *= z;
		var denominator = Double.FusedMultiplyAdd(9.0, z2, 15.0);
		denominator     = z4 + denominator;
		var result      = numerator / denominator;

		if (useReciprocal)
			result = Double.Pi / 2.0 - result;

		return Double.CopySign(result * (1.0 / Double.Pi), x);
	}

	// ── improved implementations ────────────────────────────────────────────

	/// <summary>
	/// Branchless range reduction + A&amp;S §4.4.43 5-term minimax polynomial pre-divided by π.
	/// For |x| > 1: a = 1/|x| ∈ [0,1]; atanpi(x) = sign(x)*(0.5 − atanpi(a)).
	/// Polynomial: atanpi(a)/a = c₁ + u*(c₃ + u*(c₅ + u*(c₇ + u*c₉))), u = a², cₖ = Aₖ/π.
	/// Quadrant adjustments compile to conditional-move instructions on x86/ARM64.
	/// </summary>
	private static float FastAtanPiFloatV2(float x)
	{
		if (float.IsNaN(x)) return float.NaN;
		var absX = float.Abs(x);
		var swap = absX > 1.0f;
		var a = swap ? 1.0f / absX : absX;
		var u = a * a;

		// A&S §4.4.43 original coefficients divided by π — max |ε| ≈ 3.5e-6
		var p = float.FusedMultiplyAdd(u,  0.0066322f, -0.0271011f);
		p      = float.FusedMultiplyAdd(u, p,           0.0573301f);
		p      = float.FusedMultiplyAdd(u, p,          -0.1051070f);
		p      = float.FusedMultiplyAdd(u, p,           0.3182672f);
		p     *= a;

		p = swap ? 0.5f - p : p;
		return float.IsNegative(x) ? -p : p;
	}

	/// <summary>
	/// Steinmetz 2-term with π-scaled coefficients: atanpi(a) ≈ a*(0.25 + (0.273/π)*(1−a)).
	/// Rewritten as FMA(−0.273/π, a, 0.25+0.273/π) * a — 1 FMA + 1 mul.
	/// 0.273/π ≈ 0.086916; 0.25 + 0.086916 = 0.336916.
	/// atanpi(0) = 0 and atanpi(1) = 0.25 hold exactly; 0.273 is the minimax constant.
	/// </summary>
	private static float FastAtanPiFloatV3(float x)
	{
		if (float.IsNaN(x)) return float.NaN;
		var absX = float.Abs(x);
		var swap = absX > 1.0f;
		var a = swap ? 1.0f / absX : absX;

		// π/4/π = 0.25; 0.273/π ≈ 0.086916
		var p = float.FusedMultiplyAdd(-0.086916f, a, 0.336916f) * a;

		p = swap ? 0.5f - p : p;
		return float.IsNegative(x) ? -p : p;
	}

	/// <summary>
	/// Branchless range reduction + A&amp;S §4.4.43 5-term polynomial pre-divided by π in double.
	/// Same structure as V2 float but in double arithmetic; max absolute error ≈ 3.5e-6.
	/// </summary>
	private static double FastAtanPiDoubleV2(double x)
	{
		if (double.IsNaN(x)) return double.NaN;
		var absX = double.Abs(x);
		var swap = absX > 1.0;
		var a = swap ? 1.0 / absX : absX;
		var u = a * a;

		// A&S §4.4.43 original coefficients divided by π — max |ε| ≈ 3.5e-6
		var p = double.FusedMultiplyAdd(u,  0.00663222, -0.02710107);
		p      = double.FusedMultiplyAdd(u, p,           0.05733014);
		p      = double.FusedMultiplyAdd(u, p,          -0.10510700);
		p      = double.FusedMultiplyAdd(u, p,           0.31826720);
		p     *= a;

		p = swap ? 0.5 - p : p;
		return double.IsNegative(x) ? -p : p;
	}

	/// <summary>
	/// Half-angle t = a/(1+√(1+a²)) maps a∈[0,1] → t∈[0,tan(π/8)] ≈ [0,0.4142]; then
	/// 8-term Horner Taylor series atan(t)/t = Σ (−u)^n/(2n+1) scaled by 2/π.
	/// Identity: atanpi(a) = (2/π)·atan(t).  One sqrt; truncation error ≈ 4e-8·π/2 ≈ 6e-8.
	/// </summary>
	private static double FastAtanPiDoubleV3(double x)
	{
		if (double.IsNaN(x)) return double.NaN;
		var absX = double.Abs(x);
		var swap = absX > 1.0;
		var a = swap ? 1.0 / absX : absX;

		// Half-angle reduction: atanpi(a) = (2/π)·atan(t),  t = a/(1+√(1+a²))
		var t = a / (1.0 + Math.Sqrt(1.0 + a * a));
		var u = t * t;

		// 8-term Horner Taylor: atan(t)/t = 1 − u/3 + u²/5 − … + (−u)⁷/15
		var p = double.FusedMultiplyAdd(u, -1.0 / 15.0,  1.0 / 13.0);
		p      = double.FusedMultiplyAdd(u, p,           -1.0 / 11.0);
		p      = double.FusedMultiplyAdd(u, p,            1.0 /  9.0);
		p      = double.FusedMultiplyAdd(u, p,           -1.0 /  7.0);
		p      = double.FusedMultiplyAdd(u, p,            1.0 /  5.0);
		p      = double.FusedMultiplyAdd(u, p,           -1.0 /  3.0);
		p      = double.FusedMultiplyAdd(u, p,            1.0);
		p = (2.0 / Math.PI) * t * p; // atanpi(a) = (2/π)·atan(t)

		p = swap ? 0.5 - p : p;
		return double.IsNegative(x) ? -p : p;
	}
}




